import { TargetType } from '../type';

// 下载文件时，阻止浏览器默认加载
export const downloadFile = (uri: string, fileName: string) => {
    const request = new XMLHttpRequest();
    request.responseType = 'blob'; // 定义响应类型
    request.open('GET', uri);
    request.addEventListener('load', function () {
        const url = window.URL.createObjectURL(this.response);
        const a = document.createElement('a');
        document.body.append(a);
        a.href = url;
        a.download = fileName;
        a.click();
    });
    request.send();
};

// 基于 url 下载文件
export function downloadFileFromUrl(url: string, fileName?: string, target: TargetType = '_self') {
    // create link
    const link = document.createElement('a');
    link.style.display = 'none';

    link.href = url;
    fileName && (link.download = fileName);
    link.target = target;
    // dispatch click event on link
    let event;
    try {
        event = new MouseEvent('click');
    } catch {
        event = document.createEvent('MouseEvent');
        event.initMouseEvent(
            'click',
            true,
            true,
            window,
            0,
            0,
            0,
            0,
            0,
            false,
            false,
            false,
            false,
            0,
            null
        );
    }
    link.dispatchEvent(event);
}

// 在本地生成文件并下载
export function downloadFileFromLocal(blob: Blob, fileName: string, type: string) {
    // It is necessary to create a new blob object with mime-type explicitly set for all browsers except Chrome, but it works for Chrome too.
    const newBlob = new Blob([blob], { type });

    // MS Edge and IE don't allow using a blob object directly as link href, instead it is necessary to use msSaveOrOpenBlob
    if (window.navigator && (window.navigator as any).msSaveOrOpenBlob) {
        (window.navigator as any).msSaveOrOpenBlob(newBlob);
    } else {
        // For other browsers: create a link pointing to the ObjectURL containing the blob.
        const objUrl = window.URL.createObjectURL(newBlob);

        downloadFileFromUrl(objUrl, fileName);

        // For Firefox it is necessary to delay revoking the ObjectURL.
        setTimeout(() => {
            (window.URL || window.webkitURL || window).revokeObjectURL(objUrl);
        }, 250);
    }
}

/** 获取后缀 */
export const getSuffix = (src: string, searchString = '.') =>
    src.slice(src.lastIndexOf(searchString) + 1);

/** 获取链接文件名 */
export const getLinkFileName = (link: string) => getSuffix(link, '/');
